const raw = items[0]?.json || {};
const payload = raw.payload && typeof raw.payload === 'object' && !Array.isArray(raw.payload) ? raw.payload : raw;
const researchId = payload.research_id || payload.researchId || raw.research_id || raw.researchId;
const taskId = payload.task_id || payload.taskId || raw.task_id || raw.taskId;
const topic = payload.topic || raw.topic;
if (!researchId) throw new Error('Missing research_id / researchId');
if (!taskId) throw new Error('Missing task_id / taskId');
if (!topic) throw new Error('Missing topic');
const questions = Array.isArray(payload.questions) ? payload.questions : Array.isArray(raw.questions) ? raw.questions : [];
const sourceUrls = Array.isArray(payload.source_urls)
  ? payload.source_urls
  : Array.isArray(payload.sourceUrls)
    ? payload.sourceUrls
    : Array.isArray(raw.source_urls)
      ? raw.source_urls
      : Array.isArray(raw.sourceUrls)
        ? raw.sourceUrls
        : [];
return [{
  json: {
    meta: {
      workflow_name: 'Research_Brief',
      timestamp: new Date().toISOString(),
      trigger_source: raw.trigger_source || 'research_request_webhook',
      risk_level: raw.risk_level || 'medium'
    },
    context: {
      canonical_links: [
        '[[07-Research/Research-Index|Research Index]]',
        '[[08-Runbooks/System/Escalation-Matrix|Escalation Matrix]]'
      ],
      constraints: [
        'Only use explicit official source URLs',
        'Do not invent facts beyond fetched source extracts'
      ]
    },
    payload: {
      research_id: String(researchId),
      task_id: String(taskId),
      topic: String(topic),
      questions: questions.map((entry) => String(entry)).filter(Boolean),
      target_sources: Array.isArray(payload.target_sources) ? payload.target_sources : Array.isArray(raw.target_sources) ? raw.target_sources : [],
      related_links: Array.isArray(payload.related_links) ? payload.related_links : Array.isArray(raw.related_links) ? raw.related_links : [],
      source_urls: sourceUrls.map((entry) => String(entry)).filter(Boolean)
    }
  }
}];

const item = items[0]?.json || {};
const required = ['agent', 'workflow', 'status', 'research_id', 'task_id', 'facts', 'inferences', 'open_questions', 'source_summary', 'escalate_to', 'reason', 'next_step'];
for (const key of required) {
  if (!(key in item)) throw new Error(`Missing required key: ${key}`);
}
const allowedStatus = new Set(['done', 'partial', 'blocked', 'needs_review', 'queued']);
if (!allowedStatus.has(item.status)) throw new Error(`Invalid status: ${item.status}`);
const allowedEscalation = new Set(['none', 'AI-1', 'AI-2', 'AI-3', 'AI-5', 'AI-6', 'AI-7', 'AI-8', 'AI-9', 'AI-10', 'AI-11', 'Owner']);
if (!allowedEscalation.has(item.escalate_to)) throw new Error(`Invalid escalate_to: ${item.escalate_to}`);
item.execution_summary = {
  facts_count: Array.isArray(item.facts) ? item.facts.length : 0,
  inference_count: Array.isArray(item.inferences) ? item.inferences.length : 0,
  source_count: Array.isArray(item.source_summary) ? item.source_summary.length : 0,
  requires_follow_up: item.status !== 'done'
};
return [{ json: item }];
